import React, { useState, useEffect } from 'react';
import {
  TextField,
  Button,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Box,
  Grid,
  Typography,
} from '@mui/material';
import { createProductType, updateProductType } from '../services/api';

const categoryOptions = ['Asset', 'Consumable'];
const assetTypeOptions = ['Asset', 'Consumable', 'Component'];
const assetCategoryTypeOptions = ['IT', 'Non IT'];

const ProductTypeForm = ({ editing, onSave, onClose, productTypes }) => {
  const [formData, setFormData] = useState({
    display_name: '',
    api_name: '',
    display_plural_name: '',
    api_plural_name: '',
    category: '',
    parent_product_type: '',
    asset_type: '',
    asset_category_type: '',
    description: '',
  });

  useEffect(() => {
    if (editing) {
      setFormData(editing);
    } else {
      setFormData({
        display_name: '',
        api_name: '',
        display_plural_name: '',
        api_plural_name: '',
        category: '',
        parent_product_type: '',
        asset_type: '',
        asset_category_type: '',
        description: '',
      });
    }
  }, [editing]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSave = async () => {
    try {
      if (editing) {
        await updateProductType(editing.id, formData);
      } else {
        await createProductType(formData);
      }
      onSave();
    } catch (error) {
      console.error('Error saving product type:', error);
    }
  };

  return (
    <Box component="form" sx={{ mt: 2, minWidth: 600, px: 1, pb: 1 }}>
      <Grid container spacing={3}>
        <Grid item xs={12} sm={6}>
          <TextField
            fullWidth
            required
            label="Display Name"
            name="display_name"
            value={formData.display_name}
            onChange={handleChange}
          />
        </Grid>
        <Grid item xs={12} sm={6}>
          <TextField
            fullWidth
            required
            label="API Name"
            name="api_name"
            value={formData.api_name}
            onChange={handleChange}
          />
        </Grid>
        <Grid item xs={12} sm={6}>
          <TextField
            fullWidth
            required
            label="Display Plural Name"
            name="display_plural_name"
            value={formData.display_plural_name}
            onChange={handleChange}
          />
        </Grid>
        <Grid item xs={12} sm={6}>
          <TextField
            fullWidth
            required
            label="API Plural Name"
            name="api_plural_name"
            value={formData.api_plural_name}
            onChange={handleChange}
          />
        </Grid>
        <Grid item xs={12} sm={6}>
          <FormControl fullWidth required>
            <InputLabel id="category-label">Category</InputLabel>
            <Select
              labelId="category-label"
              id="category-select"
              name="category"
              value={formData.category}
              onChange={handleChange}
              label="Category"
              displayEmpty
              renderValue={(selected) => selected || '-- Select Category --'}
            >
              {categoryOptions.map((option) => (
                <MenuItem key={option} value={option}>
                  {option}
                </MenuItem>
              ))}
            </Select>
          </FormControl>
        </Grid>
        <Grid item xs={12} sm={6}>
          <FormControl fullWidth>
            <InputLabel id="parent-label">Parent Product Type</InputLabel>
            <Select
              labelId="parent-label"
              id="parent-select"
              name="parent_product_type"
              value={formData.parent_product_type}
              onChange={handleChange}
              label="Parent Product Type"
              displayEmpty
              renderValue={(selected) => selected || '-- Select Parent --'}
            >
              <MenuItem value="">
                <em>None</em>
              </MenuItem>
              {productTypes.map((pt) => (
                <MenuItem key={pt.id} value={pt.id}>
                  {pt.display_name}
                </MenuItem>
              ))}
            </Select>
          </FormControl>
        </Grid>
        <Grid item xs={12} sm={6}>
          <FormControl fullWidth required>
            <InputLabel id="asset-type-label">Asset Type</InputLabel>
            <Select
              labelId="asset-type-label"
              id="asset-type-select"
              name="asset_type"
              value={formData.asset_type}
              onChange={handleChange}
              label="Asset Type"
              displayEmpty
              renderValue={(selected) => selected || '-- Select Asset Type --'}
            >
              {assetTypeOptions.map((option) => (
                <MenuItem key={option} value={option}>
                  {option}
                </MenuItem>
              ))}
            </Select>
          </FormControl>
        </Grid>
        <Grid item xs={12} sm={6}>
          <TextField
            fullWidth
            label="Description"
            name="description"
            value={formData.description}
            onChange={handleChange}
            multiline
            minRows={1}
            maxRows={4}
          />
        </Grid>
        <Grid item xs={12} sm={6}>
          <FormControl fullWidth required>
            <InputLabel id="asset-category-label">Asset Category Type</InputLabel>
            <Select
              labelId="asset-category-label"
              id="asset-category-select"
              name="asset_category_type"
              value={formData.asset_category_type}
              onChange={handleChange}
              label="Asset Category Type"
              displayEmpty
              renderValue={(selected) => selected || '-- Select Asset Category --'}
            >
              {assetCategoryTypeOptions.map((option) => (
                <MenuItem key={option} value={option}>
                  {option}
                </MenuItem>
              ))}
            </Select>
          </FormControl>
        </Grid>

        <Grid item xs={12}>
          <Box sx={{ mt: 3, display: 'flex', justifyContent: 'flex-end', gap: 1 }}>
            <Button variant="outlined" onClick={onClose} sx={{ minWidth: 100 }}>
              Close
            </Button>
            <Button variant="contained" onClick={handleSave} sx={{ minWidth: 100 }}>
              Save
            </Button>
          </Box>
        </Grid>
      </Grid>
    </Box>
  );
};

export default ProductTypeForm;
